     3→import { useState, useEffect, useCallback, useRef } from "react";
     4→import { socket } from "@/lib/socket";
     5→import {
     6→  getUser,
     7→  updateProfile,
     8→  uploadSelfie,
     9→  startScrape,
    10→  submitOnboarding,
    11→  UserProfile,
    12→} from "@/lib/api";
    13→import type { OnboardingData } from "@/lib/types";
    14→import GoogleSignIn from "@/components/phone/GoogleSignIn";
