   409→      </h2>
   410→
   411→      <div className="h-10 flex items-center">
   412→        <p className="text-zinc-500 text-center text-xs animate-pulse transition-all">
   413→          {TIPS[tipIndex]}
   414→        </p>
   415→      </div>
   416→
   417→      <div className="text-zinc-400 text-xs font-mono">
   418→        {String(minutes).padStart(2, "0")}:{String(seconds).padStart(2, "0")}
   419→      </div>
   420→    </div>
   421→  );
   422→}
