     7→/** Request helper for the Python backend (absolute URL). */
     8→async function request<T>(path: string, options?: RequestInit): Promise<T> {
     9→  const res = await fetch(`${API_URL}${path}`, {
    10→    headers: { "Content-Type": "application/json" },
    11→    ...options,
    12→  });
    13→  if (!res.ok) {
    14→    const body = await res.json().catch(() => ({}));
    15→    throw new Error(body.detail || `Request failed: ${res.status}`);
    16→  }
    17→  return res.json();
    18→}
    19→
    20→/** Request helper for Next.js API routes (relative path, runs on Vercel). */
    21→async function localRequest<T>(path: string, options?: RequestInit): Promise<T> {
    22→  const res = await fetch(path, {
    23→    headers: { "Content-Type": "application/json" },
    24→    ...options,
    25→  });
    26→  if (!res.ok) {
    27→    const body = await res.json().catch(() => ({}));
    28→    throw new Error(body.detail || body.error || `Request failed: ${res.status}`);
    29→  }
    30→  return res.json();
    31→}
