    48→export function googleLogin(code: string, redirectUri: string = "postmessage") {
    49→  return localRequest<UserProfile>("/api/auth/google", {
    50→    method: "POST",
    51→    body: JSON.stringify({ code, redirect_uri: redirectUri }),
    52→  });
    53→}
