    55→export function updateProfile(userId: string, name: string, phone?: string) {
    56→  const payload: { user_id: string; name: string; phone?: string } = {
    57→    user_id: userId,
    58→    name,
    59→  };
    60→  if (phone !== undefined) payload.phone = phone;
    61→  return localRequest<UserProfile>("/api/auth/profile", {
    62→    method: "POST",
    63→    body: JSON.stringify(payload),
    64→  });
    65→}
    66→
    67→export function uploadSelfie(userId: string, selfieBase64: string) {
    68→  return localRequest<UserProfile>("/api/auth/selfie", {
    69→    method: "POST",
    70→    body: JSON.stringify({ user_id: userId, selfie_base64: selfieBase64 }),
    71→  });
    72→}
    73→
    74→export function joinQueue(userId: string) {
    75→  return localRequest<QueueInfo>("/api/queue/join", {
    76→    method: "POST",
    77→    body: JSON.stringify({ user_id: userId }),
    78→  });
    79→}
    80→
    81→export function getQueueStatus(userId: string) {
    82→  return localRequest<QueueInfo>(`/api/queue/status/${userId}`);
