     1→import { NextRequest, NextResponse } from "next/server";
     2→import { getDb } from "@/lib/db";
     3→
     4→export async function POST(
     5→  req: NextRequest,
     6→  { params }: { params: Promise<{ userId: string }> }
     7→) {
     8→  try {
     9→    const { userId } = await params;
    10→    const data = await req.json();
    11→    const sql = getDb();
    12→
    13→    await sql.query(
    14→      `INSERT INTO style_profiles (user_id, brands, price_range, style_tags, size_info)
    15→       VALUES ($1::uuid, $2, $3::jsonb, $4, $5::jsonb)
    16→       ON CONFLICT (user_id)
    17→       DO UPDATE SET
    18→         brands = EXCLUDED.brands,
    19→         price_range = EXCLUDED.price_range,
    20→         style_tags = EXCLUDED.style_tags,
    21→         size_info = EXCLUDED.size_info`,
    22→      [
    23→        userId,
    24→        data.favorite_brands || [],
    25→        JSON.stringify(data.price_range || {}),
    26→        data.style_preferences || [],
    27→        JSON.stringify(data.size_info || {}),
    28→      ]
    29→    );
    30→
    31→    return NextResponse.json({ status: "success", message: "Onboarding completed" });
    32→  } catch (err) {
    33→    const message = err instanceof Error ? err.message : "Failed to save onboarding";
    34→    return NextResponse.json({ error: message }, { status: 500 });
    35→  }
    36→}
