    17→
    18→type PhoneState = "loading" | "signin" | "questionnaire" | "queue" | "idle" | "recap";
    19→
    20→const STORAGE_KEY = "mirrorless_user_id";
    21→
    22→export default function PhonePage() {
    23→  const [state, setState] = useState<PhoneState>("loading");
    24→  const [user, setUser] = useState<UserProfile | null>(null);
    25→  const [error, setError] = useState("");
    26→  const [recapData, setRecapData] = useState<{
    27→    summary?: string;
    28→    items_shown?: number;
    29→    items_liked?: number;
    30→  }>({});
    31→
    32→  // Shape of the actual session_ended payload from backend
    33→  interface SessionEndedPayload {
    34→    summary?: string;
    35→    stats?: { items_shown: number; likes: number; dislikes: number };
    36→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
    37→    user_name?: string;
    38→  }
    39→
    40→  // Check for returning user on mount
    41→  useEffect(() => {
    42→    async function checkReturning() {
    43→      const savedId = localStorage.getItem(STORAGE_KEY);
    44→      if (savedId) {
    45→        try {
    46→          const existingUser = await getUser(savedId);
    47→          setUser(existingUser);
    48→          setState("queue");
    49→          return;
    50→        } catch {
    51→          localStorage.removeItem(STORAGE_KEY);
    52→        }
    53→      }
    54→      setState("signin");
    55→    }
    56→    checkReturning();
    57→  }, []);
    58→
    59→  // Connect socket when we have a user
    60→  useEffect(() => {
    61→    if (!user) return;
    62→    socket.connect();
    63→    socket.emit("join_room", { user_id: user.id });
    64→
    65→    const handleSessionEnded = (data: SessionEndedPayload) => {
    66→      setRecapData({
    67→        summary: data?.summary,
    68→        items_shown: data?.stats?.items_shown,
    69→        items_liked: data?.stats?.likes,
    70→      });
    71→      setState("recap");
    72→    };
    73→
    74→    socket.on("session_ended", handleSessionEnded);
    75→
    76→    return () => {
    77→      socket.off("session_ended", handleSessionEnded);
    78→    };
    79→  }, [user]);
    80→
    81→  const handleSignInComplete = useCallback(
    82→    (profile: UserProfile, selfieBase64: string | null, displayName: string) => {
    83→      setUser(profile);
    84→      localStorage.setItem(STORAGE_KEY, profile.id);
    85→
    86→      // Fire-and-forget: update name, upload selfie, start scrape
    87→      updateProfile(profile.id, displayName).catch(() => {});
    88→      if (selfieBase64) {
    89→        uploadSelfie(profile.id, selfieBase64).catch(() => {});
    90→      }
    91→      startScrape(profile.id).catch(() => {});
    92→
    93→      setState("questionnaire");
    94→    },
    95→    []
    96→  );
    97→
    98→  const handleQuestionnaireSubmit = useCallback(
    99→    async (data: OnboardingData) => {
   100→      if (!user) return;
   101→      await submitOnboarding(user.id, data);
   102→      setState("queue");
   103→    },
   104→    [user]
   105→  );
   106→
   107→  const handleBecameActive = useCallback(() => {
   108→    setState("idle");
   109→  }, []);
   110→
   111→  const handleLeaveQueue = useCallback(() => {
   112→    localStorage.removeItem(STORAGE_KEY);
   113→    setUser(null);
   114→    setState("signin");
   115→  }, []);
   116→
   117→  const handleDone = useCallback(() => {
   118→    localStorage.removeItem(STORAGE_KEY);
   119→    setUser(null);
   120→    setRecapData({});
   121→    setState("signin");
   122→  }, []);
   123→
   124→  if (state === "loading") {
   125→    return (
   126→      <main className="min-h-screen bg-white flex items-center justify-center">
   127→        <p className="text-zinc-400 animate-pulse">Loading...</p>
   128→      </main>
   129→    );
   130→  }
   131→
   132→  return (
   133→    <main className="min-h-screen bg-white text-zinc-900">
   134→      {state === "signin" && (
   135→        <SignInView onComplete={handleSignInComplete} error={error} setError={setError} />
   136→      )}
   137→      {state === "questionnaire" && (
   138→        <QuestionnaireView onSubmit={handleQuestionnaireSubmit} />
   139→      )}
   140→      {state === "queue" && user && (
   141→        <div className="flex flex-col items-center justify-center min-h-screen p-4">
