   155→function SignInView({
   156→  onComplete,
   157→  error,
   158→  setError,
   159→}: {
   160→  onComplete: (user: UserProfile, selfie: string | null, name: string) => void;
   161→  error: string;
   162→  setError: (e: string) => void;
   163→}) {
   164→  const [name, setName] = useState("");
   165→  const [selfie, setSelfie] = useState<string | null>(null);
   166→  const [oauthUser, setOauthUser] = useState<UserProfile | null>(null);
   167→
   168→  const handleGoogleSuccess = useCallback(
   169→    (user: UserProfile) => {
   170→      setOauthUser(user);
   171→      if (!name && user.name) setName(user.name);
   172→    },
   173→    [name]
   174→  );
   175→
   176→  const handleContinue = useCallback(() => {
   177→    if (!oauthUser) {
   178→      setError("Please sign in with Google first.");
   179→      return;
   180→    }
   181→    if (!name.trim()) {
   182→      setError("Please enter your name.");
   183→      return;
   184→    }
   185→    onComplete(oauthUser, selfie, name.trim());
   186→  }, [oauthUser, selfie, name, onComplete, setError]);
   187→
   188→  return (
   189→    <div className="flex flex-col items-center justify-center min-h-screen p-4 gap-4">
   190→      <div className="text-center">
   191→        <h1 className="text-2xl font-bold mb-1">Mirrorless</h1>
   192→        <p className="text-zinc-500 text-sm">Your AI stylist awaits</p>
   193→      </div>
   194→
   195→      <SelfieCapture onCapture={setSelfie} />
   196→
   197→      <div className="w-full max-w-sm">
   198→        <label className="block text-sm font-semibold mb-1">Your name</label>
   199→        <input
   200→          value={name}
   201→          onChange={(e) => setName(e.target.value)}
   202→          placeholder="Enter your name"
   203→          className="w-full px-3 py-2.5 border border-zinc-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-zinc-900"
   204→        />
   205→      </div>
   206→
   207→      {!oauthUser ? (
   208→        <GoogleSignIn
   209→          onSuccess={handleGoogleSuccess}
   210→          onError={setError}
   211→        />
   212→      ) : (
   213→        <div className="flex items-center gap-2 text-sm text-green-600">
   214→          <span>✓</span>
   215→          <span>Signed in as {oauthUser.email}</span>
   216→        </div>
   217→      )}
   218→
   219→      {oauthUser && (
   220→        <button
   221→          onClick={handleContinue}
   222→          className="w-full max-w-sm bg-zinc-900 text-white rounded-xl py-3 text-sm font-semibold"
   223→        >
   224→          Continue
   225→        </button>
   226→      )}
   227→
   228→      {error && <p className="text-red-500 text-sm text-center">{error}</p>}
   229→    </div>
   230→  );
   231→}
