   389→    const clockTimer = setInterval(() => {
   390→      setElapsed((s) => s + 1);
   391→    }, 1000);
   392→    return () => {
   393→      clearInterval(tipTimer);
   394→      clearInterval(clockTimer);
   395→    };
   396→  }, []);
   397→
   398→  const minutes = Math.floor(elapsed / 60);
   399→  const seconds = elapsed % 60;
   400→
   401→  return (
   402→    <div className="flex flex-col items-center justify-center min-h-screen p-4 gap-4">
